pub(super) const SCOPE_DEV_USER_EMAIL_ENV: &str = "SCOPE_DEV_USER_EMAIL";
pub(super) const SCOPE_DEV_USER_HANDLE_ENV: &str = "SCOPE_DEV_USER_HANDLE";

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub(super) enum DevMetadataStore {
