pub fn is_local_dev_env() -> bool {
    non_empty_env(SCOPE_ENV_ENV).as_deref() == Some(LOCAL_SCOPE_ENV)
}

pub(super) fn validate_local_dev_environment() -> anyhow::Result<LocalDevSettings> {
    let snapshot = DevEnvSnapshot::from_env();
